import React, { useState, useEffect } from 'react';
import CustomerView from './customerview/CustomerView';
import AdminLogin from './admin/AdminLogin';
import AdminDashboard from './admin/AdminDashboard';
import UserManagement from './admin/user/UserManagement';
import OrderManagement from './admin/order/OrderManagement';
import ProductManagement from './admin/product/ProductManagement';
import AdminSidebar from './admin/AdminSidebar';

// Main app with customer and admin flows
export default function App() {
  const [adminStep, setAdminStep] = useState('customer'); // 'customer', 'login', 'dashboard', 'user', 'order', 'product'
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // Check login on mount
  useEffect(() => {
    const token = localStorage.getItem('adminToken');
    setIsAdminLoggedIn(!!token);
    if (token && adminStep === 'login') setAdminStep('dashboard');
    if (!token && ["dashboard", "user", "order", "product"].includes(adminStep)) setAdminStep('login');
  }, [adminStep]);

  // Navigation handler for admin dashboard
  const handleAdminNavigate = (section) => setAdminStep(section);
  const handleAdminLogout = () => {
    localStorage.removeItem('adminToken');
    setIsAdminLoggedIn(false);
    setAdminStep('login');
  };

  if (adminStep === 'login') return <AdminLogin onLogin={() => { setIsAdminLoggedIn(true); setAdminStep('dashboard'); }} />;

  // Admin pages with sidebar (protected)
  if (["dashboard", "user", "order", "product"].includes(adminStep) && isAdminLoggedIn) {
    let content = null;
    if (adminStep === 'dashboard') content = <AdminDashboard onNavigate={handleAdminNavigate} />;
    if (adminStep === 'user') content = <UserManagement />;
    if (adminStep === 'order') content = <OrderManagement />;
    if (adminStep === 'product') content = <ProductManagement />;
    return (
      <div className="flex min-h-screen bg-gray-50">
        <AdminSidebar current={adminStep} onNavigate={handleAdminNavigate} onLogout={handleAdminLogout} />
        <div className="flex-1">{content}</div>
      </div>
    );
  }

  // Show customer view with a button to enter admin login
  return <>
    <CustomerView />
    <button onClick={() => setAdminStep('login')} style={{ position: 'fixed', bottom: 24, right: 24, background: '#222', color: '#fff', borderRadius: 8, padding: '10px 22px', fontWeight: 600, fontSize: 16, boxShadow: '0 2px 8px #2222', zIndex: 2000 }}>Admin Login</button>
  </>;
}
